+use std::collections::{BTreeMap, BTreeSet, VecDeque};
+
+use crate::core_a::R0;
+
+fn lane_key(r: &R0) -> String {
+    r.lane_name.clone()
+}
+
+/// Accept work in discrete turns.
+///
+/// Contract:
+/// - Each row becomes eligible on its own arrival/base_turn.
+/// - Per turn, each lane may accept up to `cap` ready rows.
+/// - Overflow stays live for later turns.
+/// - Accepted trace is ordered by accepted turn asc, then lane name asc,
+///   then plan-file order (seq) within the lane.
+pub fn fold_b(rows: &[R0], cap: usize) -> Vec<R0> {
+    let cap = cap.max(1);
+
+    // Dedup by logical task name: keep the earliest (base_turn, seq).
+    let mut uniq: BTreeMap<String, R0> = BTreeMap::new();
+    for r in rows.iter().cloned() {
+        uniq.entry(r.task_name.clone())
+            .and_modify(|cur| {
+                if (r.base_turn, r.seq) < (cur.base_turn, cur.seq) {
+                    *cur = r.clone();
+                }
+            })
+            .or_insert(r);
+    }
+    let mut rows: Vec<R0> = uniq.into_values().collect();
+
+    // Establish timeline.
+    let mut turns: BTreeSet<u64> = BTreeSet::new();
+    for r in &rows {
+        turns.insert(r.base_turn);
+    }
+    if turns.is_empty() {
+        return Vec::new();
+    }
+    let min_turn = *turns.iter().next().unwrap();
+    let max_turn = *turns.iter().next_back().unwrap();
+
+    // Bucket arrivals by turn, then by lane.
+    let mut arrivals: BTreeMap<u64, BTreeMap<String, Vec<R0>>> = BTreeMap::new();
+    for r in rows.drain(..) {
+        arrivals
+            .entry(r.base_turn)
+            .or_default()
+            .entry(lane_key(&r))
+            .or_default()
+            .push(r);
+    }
+    for (_t, by_lane) in arrivals.iter_mut() {
+        for (_lane, v) in by_lane.iter_mut() {
+            v.sort_by_key(|r| r.seq);
+        }
+    }
+
+    // Per-lane ready queues.
+    let mut ready: BTreeMap<String, VecDeque<R0>> = BTreeMap::new();
+    let mut accepted: Vec<R0> = Vec::new();
+
+    // Drive turns from min..=max, and then keep going until all ready drained.
+    let mut t = min_turn;
+    loop {
+        if let Some(by_lane) = arrivals.remove(&t) {
+            for (lane, v) in by_lane {
+                let q = ready.entry(lane).or_default();
+                for r in v {
+                    q.push_back(r);
+                }
+            }
+        }
+
+        // Accept per lane in lane-name order.
+        for (lane, q) in ready.iter_mut() {
+            let mut took = 0usize;
+            while took < cap {
+                let mut r = match q.pop_front() {
+                    Some(r) => r,
+                    None => break,
+                };
+                r.turn = t;
+                // keep lane field stable, but ensure it matches key
+                r.lane_name = lane.clone();
+                accepted.push(r);
+                took += 1;
+            }
+        }
+
+        let any_ready = ready.values().any(|q| !q.is_empty());
+        let any_future = !arrivals.is_empty();
+
+        if !any_ready && !any_future {
+            break;
+        }
+        if t < max_turn {
+            t += 1;
+        } else {
+            // past last arrival turn, just keep draining ready
+            t += 1;
+        }
+    }
+
+    accepted.sort_by(|l, r| {
+        l.turn
+            .cmp(&r.turn)
+            .then(l.lane_name.cmp(&r.lane_name))
+            .then(l.seq.cmp(&r.seq))
+    });
+    accepted
+}
