use crate::types_f::{CaseReport, Record};

fn esc(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

pub fn row_json(row: &Record) -> String {
    format!(
        "{{\"case\":\"{}\",\"task\":\"{}\",\"parent\":\"{}\",\"depth\":{},\"lane\":\"{}\",\"turn\":{}}}",
        esc(&row.case_name),
        esc(&row.task_name),
        esc(&row.parent_name),
        row.depth,
        esc(&row.lane_name),
        row.turn
    )
}

fn string_array(items: &[String]) -> String {
    format!(
        "[{}]",
        items
            .iter()
            .map(|s| format!("\"{}\"", esc(s)))
            .collect::<Vec<_>>()
            .join(",")
    )
}

